patch:
--- a/comparator.sv
+++ b/comparator.sv
@@ -1,6 +1,6 @@
 module mag_comparator (
   input [7:0] a,
   input [7:0] b,
-  output reg greater, equal, lesser, unused_port
+  output reg greater, equal, lesser
 );

   always @(*) begin
@@ -16,7 +16,7 @@
 module cmp_wrapper (
   input [7:0] x, y,
   output gt, eq, lt
 );

-  mag_comparator cmp (.a(x), .b(y), .greater(gt), .equal(eq), .lesser(lt), .unused_port());
+  mag_comparator cmp (.a(x), .b(y), .greater(gt), .equal(eq), .lesser(lt));

 endmodule

before_code:
module mag_comparator (
  input [7:0] a,
  input [7:0] b,
  output reg greater, equal, lesser, unused_port
);

  always @(*) begin
    if (a > b) begin
      greater = 1'b1;
      equal = 1'b0;
      lesser = 1'b0;
    end else if (a == b) begin
      greater = 1'b0;
      equal = 1'b1;
      lesser = 1'b0;
    end else begin
      greater = 1'b0;
      equal = 1'b0;
      lesser = 1'b1;
    end
    unused_port = 1'b0;
  end
endmodule

module cmp_wrapper (
  input [7:0] x, y,
  output gt, eq, lt
);

  mag_comparator cmp (.a(x), .b(y), .greater(gt), .equal(eq), .lesser(lt), .unused_port());

endmodule

after_code:
